What does this program print?

```cpp
#include <iostream>
struct Widget {
    int val;
    Widget(int v) : val{v} { std::cout << "C" << v << " "; }
    Widget(const Widget& o) : val{o.val} { std::cout << "CP" << o.val << " "; }
};
Widget make(int x) { return Widget{x}; }
int main() {
    Widget w = make(7);
    std::cout << w.val << "\n";
}
```

A student wants to verify that copy elision prevents the copy constructor from running when returning a local variable. They run this and expect to see only `ctor` printed, but they also see `copy`. What is the bug?

```cpp
#include <iostream>
struct Box {
    int v;
    Box(int x) : v{x} { std::cout << "ctor\n"; }
    Box(const Box& o) : v{o.v} { std::cout << "copy\n"; }
};
Box make() {
    Box b{42};
    return b;
}
int main() {
    Box result = make();
    std::cout << result.v << "\n";
}
```

What does this program print? Assume C++17 or later.

```cpp
#include <iostream>
struct Tag {
    Tag() { std::cout << "default "; }
    Tag(int) { std::cout << "int-ctor "; }
    Tag(const Tag&) { std::cout << "copy "; }
};
int main() {
    Tag a = {5};   // copy-list init
    Tag b = a;     // copy init from lvalue
    std::cout << "done\n";
}
```

